    /// use tree_sitter_language_pack::{ExtractionConfig, ExtractionPattern, CaptureOutput, extract_patterns};
    ///
    /// let mut patterns = AHashMap::new();
    /// patterns.insert("fns".to_string(), ExtractionPattern {
    ///     query: "(function_definition name: (identifier) @fn_name)".to_string(),
    ///     capture_output: CaptureOutput::default(),
    ///     child_fields: Vec::new(),
    ///     max_results: None,
    ///     byte_range: None,
    /// });
    /// let config = ExtractionConfig { language: "python".to_string(), patterns };
    /// let result = extract_patterns("def hello(): pass", &config).unwrap();
    /// ```
    /// </summary>
    /// <param name="source"></param>
    /// <param name="config"></param>
    public static ExtractionResult ExtractPatterns(string source, ExtractionConfig config)
    {
        ArgumentNullException.ThrowIfNull(source);
        ArgumentNullException.ThrowIfNull(config);
        var configJson = JsonSerializer.Serialize(config, JsonOptions);
        var configHandle = NativeMethods.ExtractionConfigFromJson(configJson);
        var result = NativeMethods.ExtractPatterns(
            source,
            configHandle
        );
        if (result == IntPtr.Zero) { var err = GetLastError(); if (err.Code != 0) throw err; }
        var jsonPtr = NativeMethods.ExtractionResultToJson(result);
        var json = Marshal.PtrToStringUTF8(jsonPtr);
        NativeMethods.FreeString(jsonPtr);
        NativeMethods.ExtractionResultFree(result);
        var returnValue = JsonSerializer.Deserialize<ExtractionResult>(json ?? "null", JsonOptions)!;
        NativeMethods.ExtractionConfigFree(configHandle);
        return returnValue;
    }

    /// <summary>
    /// Initialize the language pack with the given configuration.
