    /// # Example
    ///
    /// ```no_run
    /// use tree_sitter_language_pack::{PackConfig, init};
    ///
    /// let config = PackConfig {
    ///     cache_dir: None,
    ///     languages: Some(vec!["python".to_string(), "rust".to_string()]),
    ///     groups: None,
    /// };
    /// init(&config).unwrap();
    /// ```
    /// </summary>
    /// <param name="config"></param>
    public static void Init(PackConfig config)
    {
        ArgumentNullException.ThrowIfNull(config);
        var configJson = JsonSerializer.Serialize(config, JsonOptions);
        var configHandle = NativeMethods.PackConfigFromJson(configJson);
        NativeMethods.Init(
            configHandle
        );
        NativeMethods.PackConfigFree(configHandle);
    }

    /// <summary>
    /// Apply download configuration without downloading anything.
    ///
    /// Use this to set a custom cache directory before the first call to
    /// [`get_language`] or any download function. Changing the cache dir
    /// after languages have been registered has no effect on already-loaded
    /// languages.
    ///
    /// # Errors
    ///
    /// Returns an error if the lock cannot be acquired.
    ///
    /// # Example
    ///
    /// ```no_run
    /// use std::path::PathBuf;
    /// use tree_sitter_language_pack::{PackConfig, configure};
    ///
    /// let config = PackConfig {
    ///     cache_dir: Some(PathBuf::from("/tmp/my-parsers")),
    ///     languages: None,
    ///     groups: None,
    /// };
    /// configure(&config).unwrap();
    /// ```
