        var configHandle = NativeMethods.PackConfigFromJson(configJson);
        NativeMethods.Configure(
            configHandle
        );
        NativeMethods.PackConfigFree(configHandle);
    }

    /// <summary>
    /// Download specific languages to the local cache.
    ///
    /// Returns the number of newly downloaded languages (languages that were
    /// already cached are not counted).
    ///
    /// # Errors
    ///
    /// Returns an error if any language is not available in the manifest or if
    /// the download fails.
    ///
    /// # Example
    ///
    /// ```no_run
    /// use tree_sitter_language_pack::download;
    ///
    /// let count = download(&["python", "rust", "typescript"]).unwrap();
    /// println!("Downloaded {} new languages", count);
    /// ```
    /// </summary>
    /// <param name="names"></param>
    public static ulong Download(List<string> names)
    {
        var namesJson = JsonSerializer.Serialize(names, JsonOptions);
        var namesHandle = Marshal.StringToHGlobalAnsi(namesJson);
        var result = NativeMethods.Download(
            namesHandle
        );
        if (result == IntPtr.Zero) { var err = GetLastError(); if (err.Code != 0) throw err; }
        var returnValue = result;
        Marshal.FreeHGlobal(namesHandle);
        return returnValue;
    }

